import { FC, Fragment } from 'react';

import {
  StyledSpecList,
  StyledSpecItem,
  StyledSpecItemWithSublist,
  StyledSubSpecList,
  StyledSubSpecItem,
  StyledIcon,
  StyledImage,
} from './SpecsList.styles';
import { SpecsListProps } from './SpecsList.types';

/**
 * This component is designed to display a list of specifications.
 * It supports rendering an optional image along with a collection of items, where each item
 * consists of a label, a value, and an optional sublist of specifications.
 * When a sublist is present, it is displayed as a nested set of specifications.
 *
 * @component
 * @example
 * Example usage of SpecsList on a product page:
 * const items = [
 *   { label: 'Best', value: 'Example Best For' },
 *   { label: 'Spec1', value: 'Value1' },
 *   {
 *     label: 'Why we love it',
 *     sublist: [
 *       { svg: TickSVG, value: 'Pro1' },
 *       { svg: TickSVG, value: 'Pro2' },
 *     ],
 *   },
 *   {
 *     label: 'Take note',
 *     sublist: [
 *       { svg: CrossSVG, value: 'Con1' },
 *       { svg: CrossSVG, value: 'Con2' },
 *     ],
 *   },
 * ];
 * <SpecsList image={<img src="example.jpg" alt="Example" />} items={items} />
 */

const SpecsList: FC<SpecsListProps> = ({ image, items }) => (
  <Fragment>
    {image && <StyledImage>{image}</StyledImage>}
    <StyledSpecList>
      {items.map(({ label, value, sublist }, index) => (
        <Fragment key={`spec-${index}`}>
          {sublist ? (
            <StyledSpecItemWithSublist>
              {label && <strong>{label} </strong>}
              {sublist.map(({ svg, value: subValue }, subIndex) => (
                <StyledSubSpecList key={`subspec-list-${subIndex}`}>
                  <StyledSubSpecItem>
                    {svg && <StyledIcon svg={svg} size="small" />}
                    {subValue}
                  </StyledSubSpecItem>
                </StyledSubSpecList>
              ))}
            </StyledSpecItemWithSublist>
          ) : (
            <StyledSpecItem>
              {label && <strong>{label}: </strong>}
              {value}
            </StyledSpecItem>
          )}
        </Fragment>
      ))}
    </StyledSpecList>
  </Fragment>
);

export default SpecsList;
